interface Entity {
  id:        number;
  createdAt: Date;
  updatedAt: Date;
}

interface User extends Entity {
  name:  string;
  email: string;
}

// User now has: id, createdAt, updatedAt, name, email
const alice: User = {
  id:        1,
  name:      "Alice",
  email:     "alice@example.com",
  createdAt: new Date(),
  updatedAt: new Date(),
};

// A function that accepts the base type also accepts the child
function logEntity(e: Entity): void {
  console.log(`[${e.id}] created ${e.createdAt.toISOString()}`);
}
logEntity(alice); // OK — User satisfies Entity (structural typing)

