interface Shape {
  kind: string;  // broad
  area(): number;
}

interface Circle extends Shape {
  kind: "circle";  // narrowed — literal type is a subtype of string
  radius: number;
}

interface Rectangle extends Shape {
  kind: "rectangle"; // narrowed
  width: number;
  height: number;
}

// Discriminated union using narrowed kinds
type Geometry = Circle | Rectangle;

function area(shape: Geometry): number {
  switch (shape.kind) {
    case "circle":    return Math.PI * shape.radius ** 2;
    case "rectangle": return shape.width * shape.height;
  }
}

