// Extend the DOM HTMLElement with a custom dataset type
interface TypedHTMLElement<T extends Record<string, string>> extends HTMLElement {
  dataset: DOMStringMap & T;
}

// Usage in a directive
@Directive({ selector: "[appTrack]" })
class TrackDirective {
  constructor(private el: ElementRef<TypedHTMLElement<{ trackId: string; trackLabel: string }>>) {}

  ngOnInit(): void {
    const { trackId, trackLabel } = this.el.nativeElement.dataset;
    // trackId: string; trackLabel: string — fully typed
    console.log(trackId, trackLabel);
  }
}

// Extend Angular ActivatedRouteSnapshot data
