// Deep chain — each level adds one concern
interface Identifiable   { id: number }
interface Timestamped extends Identifiable { createdAt: Date; updatedAt: Date }
interface Authored    extends Timestamped  { authorId: number }
interface Published   extends Authored    { publishedAt?: Date; status: "draft" | "live" }
interface Article     extends Published   { title: string; body: string; tags: string[] }

// Article now carries: id, createdAt, updatedAt, authorId, publishedAt, status, title, body, tags

// Find where a property comes from — hover in IDE or use "Go to definition"
// TypeScript understands the full chain for type narrowing

// Pitfall: overlapping property names with incompatible types
interface A { value: string }
interface B extends A { value: string } // OK — same type
// interface C extends A { value: number } // Error — number not assignable to string

// Pitfall: extending a very wide interface pollutes autocomplete
// Prefer composition (intersection types) for horizontal concerns
type WithMeta<T> = T & { meta: Record<string, unknown> };
// Doesn't pollute the Article interface with meta

// Generic base
interface Repository<T> {
  findById(id: number): Promise<T | null>;
  findAll(): Promise<T[]>;
}

// Specialised extension — adds write operations
interface MutableRepository<T extends { id: number }> extends Repository<T> {
  save(entity: T): Promise<T>;
  delete(id: number): Promise<void>;
}

// Concrete interface for a specific entity
interface UserRepository extends MutableRepository<User> {
  findByEmail(email: string): Promise<User | null>;
}

// Angular service implementing the chain
@Injectable({ providedIn: "root" })
class HttpUserRepository implements UserRepository {
  constructor(private http: HttpClient) {}

  findById(id: number)            { return firstValueFrom(this.http.get<User>(`/api/users/${id}`)); }
  findAll()                        { return firstValueFrom(this.http.get<User[]>("/api/users")); }
  save(user: User)                 { return firstValueFrom(this.http.put<User>(`/api/users/${user.id}`, user)); }
  delete(id: number)               { return firstValueFrom(this.http.delete<void>(`/api/users/${id}`)); }
  findByEmail(email: string)       { return firstValueFrom(this.http.get<User>(`/api/users?email=${email}`)); }
}

// Testable — swap with an in-memory stub
class InMemoryUserRepository implements UserRepository {
  private store: User[] = [];
  async findById(id: number)    { return this.store.find(u => u.id === id) ?? null; }
  async findAll()               { return [...this.store]; }
  async save(user: User)        { this.store.push(user); return user; }
  async delete(id: number)      { this.store = this.store.filter(u => u.id !== id); }
  async findByEmail(email: string) { return this.store.find(u => u.email === email) ?? null; }
}

// Extending — cleaner for stable class-like hierarchies
interface Base { id: number }
interface Child extends Base { name: string }

// Intersection — useful for ad-hoc composition or utility types
type WithTimestamps<T> = T & { createdAt: Date; updatedAt: Date };
type TimestampedUser = WithTimestamps<User>;

// Incompatible member: different behaviour
interface A1 { value: string }
interface A2 { value: number }

// interface Merged extends A1, A2 {} // Error: types of 'value' are incompatible

type Intersected = A1 & A2;
// Intersected.value: string & number = never — no error, just an unusable type

// Feature slices as interfaces
interface WithId      { id: number }
interface WithName    { name: string }
interface WithDates   { createdAt: Date; updatedAt: Date }
interface WithSoftDelete { deletedAt: Date | null; isDeleted: boolean }

// Compose by extending all of them
interface AuditedEntity extends WithId, WithName, WithDates, WithSoftDelete {}

// Mixin factory — creates values that satisfy the combined interface
function makeAuditedEntity(
  id: number,
  name: string,
): AuditedEntity {
  const now = new Date();
  return {
    id,
    name,
    createdAt: now,
    updatedAt: now,
    deletedAt: null,
    isDeleted: false,
  };
}

// Soft-delete helper — type-safe because interface is shared
function softDelete<T extends WithSoftDelete>(entity: T): T {
  return { ...entity, deletedAt: new Date(), isDeleted: true };
}

const user = makeAuditedEntity(1, 'Alice');
const deleted = softDelete(user); // AuditedEntity with deletedAt set
console.log(deleted.isDeleted); // true

// Each mixin is a constructor-extending function
type Constructor<T = {}> = new (...args: any[]) => T;

interface Serializable { serialize(): string }
interface Validatable  { validate(): boolean }

function withSerializable<TBase extends Constructor>(Base: TBase) {
  return class extends Base implements Serializable {
    serialize(): string { return JSON.stringify(this); }
  };
}

function withValidatable<TBase extends Constructor>(Base: TBase) {
  return class extends Base implements Validatable {
    validate(): boolean {
      return Object.values(this as Record<string, unknown>)
        .every(v => v !== null && v !== undefined);
    }
  };
}

// Compose mixins
class BaseModel {
  constructor(public id: number) {}
}

const SerializableValidatableModel = withSerializable(withValidatable(BaseModel));

class User extends SerializableValidatableModel {
  constructor(id: number, public name: string) {
    super(id);
  }
}

const u = new User(1, 'Alice');
console.log(u.serialize());  // {"id":1,"name":"Alice"}
console.log(u.validate());   // true

import { Injectable, InjectionToken } from '@angular/core';

// Base contract
interface StorageService {
  getItem(key: string): string | null;
  setItem(key: string, value: string): void;
  removeItem(key: string): void;
}

// Extended contract — adds async support and TTL
interface PersistentStorageService extends StorageService {
  getItemAsync(key: string): Promise<string | null>;
  setItemWithTTL(key: string, value: string, ttlMs: number): void;
  clear(): void;
}

// Injection token typed to the extended interface
const STORAGE = new InjectionToken<PersistentStorageService>('PersistentStorageService');

@Injectable({ providedIn: 'root' })
class LocalStorageService implements PersistentStorageService {
  getItem(key: string): string | null        { return localStorage.getItem(key); }
  setItem(key: string, value: string): void  { localStorage.setItem(key, value); }
  removeItem(key: string): void              { localStorage.removeItem(key); }

  async getItemAsync(key: string): Promise<string | null> {
    return this.getItem(key);
  }

  setItemWithTTL(key: string, value: string, ttlMs: number): void {
    const payload = JSON.stringify({ value, expiry: Date.now() + ttlMs });
    localStorage.setItem(key, payload);
  }

  clear(): void { localStorage.clear(); }
}

// Consumers only depend on the narrower StorageService where TTL is not needed
@Injectable({ providedIn: 'root' })
class CacheService {
  constructor(private storage: StorageService) {} // accepts either implementation
}

import { ActivatedRouteSnapshot, RouterStateSnapshot, Route } from '@angular/router';
import { HttpRequest, HttpHeaders } from '@angular/common/http';

// Extend Angular's Route to carry typed metadata
interface AppRoute extends Route {
  data: {
    title: string;
    requiresAuth: boolean;
    roles?: string[];
    breadcrumb?: string;
  };
  children?: AppRoute[]; // keep children typed as AppRoute too
}

const routes: AppRoute[] = [
  {
    path: 'dashboard',
    data: { title: 'Dashboard', requiresAuth: true, roles: ['admin', 'user'] },
    loadComponent: () => import('./dashboard.component').then(m => m.DashboardComponent),
  },
];

// Typed route data accessor — works on both standalone and module-based routes
function getRouteTitle(snapshot: ActivatedRouteSnapshot): string {
  return (snapshot.data as AppRoute['data']).title;
}

// Extend request metadata without touching HttpRequest generics
interface RequestMetadata {
  correlationId: string;
  source: 'web' | 'mobile';
}

function addCorrelationId(req: HttpRequest<unknown>): HttpRequest<unknown> {
  const meta: RequestMetadata = { correlationId: crypto.randomUUID(), source: 'web' };
  return req.clone({ headers: req.headers.set('X-Correlation-ID', meta.correlationId) });
}

interface Base {
  value: number | string;
}

// LEGAL — narrowing to a subset of the union
interface Narrowed extends Base {
  value: number; // string is removed from the union; number extends (number | string)
}

// ILLEGAL — widening to a type that does not extend number | string
interface Widened extends Base {
  // value: boolean; // Error: Type 'boolean' is not assignable to type 'string | number'.
}

// LEGAL — adding optional that does not conflict
interface Extended extends Base {
  label?: string;
}

const n: Narrowed = { value: 42 };         // OK
const e: Extended = { value: 'hello' };     // OK — value can still be string via Base

// Declaration merging — same name, same scope, SAME file or global
interface Window {
  myApp: { version: string };
}

// Extension — new name, can live anywhere
interface AppWindow extends Window {
  analytics: { trackEvent(name: string): void };
}

// Merging adds to the ORIGINAL type everywhere it is used
// Extension creates a NARROWER type usable only where AppWindow is referenced

// Anti-pattern: merge into a third-party interface when extension would do
// ✗ declare module 'some-lib' { interface LibType { myProp: string } } // affects all consumers
// ✓ interface ExtendedLibType extends LibType { myProp: string }       // scoped to your code

interface A { shared: number }
interface B extends A { label: string }
interface C extends A { label: string }

// Diamond: B and C both add 'label' with the same type — fine
interface D extends B, C {}
const d: D = { shared: 1, label: 'ok' };

// Diamond with CONFLICTING types — compile error
interface E extends A { shared: 'literal' }  // narrowed to literal

// interface F extends B, E {}
// Error: Named property 'shared' of types 'B' and 'E' are not identical.
// TypeScript collapses duplicate properties only when types are identical or one extends the other.
